```go
// ProcessBatch 并发处理一批任务，限制并发数，支持整体超时和单个任务超时
func ProcessBatch[T, R any](
    ctx context.Context,
    items []T,
    concurrency int,
    timeout time.Duration,
    fn func(ctx context.Context, item T) (R, error),
) ([]R, []error) {
    results := make([]R, len(items))
    errs := make([]error, len(items))

    // 用 errgroup 限制并发
    g, ctx := errgroup.WithContext(ctx)
    g.SetLimit(concurrency)

    for i, item := range items {
        i, item := i, item  // 捕获变量
        g.Go(func() error {
            // 每个任务有独立超时
            taskCtx, cancel := context.WithTimeout(ctx, timeout)
            defer cancel()

            result, err := fn(taskCtx, item)
            results[i] = result
            errs[i] = err
            return nil  // 不向 errgroup 返回 error，自行收集
        })
    }

    g.Wait()
    return results, errs
}

// 使用示例
func main() {
    ctx := context.Background()

    urls := []string{
        "https://example.com/1",
        "https://example.com/2",
        "https://example.com/3",
    }

    results, errs := ProcessBatch(
        ctx,
        urls,
        5,               // 最多 5 个并发
        3*time.Second,   // 每个请求最多 3 秒
        func(ctx context.Context, url string) ([]byte, error) {
            req, _ := http.NewRequestWithContext(ctx, "GET", url, nil)
            resp, err := http.DefaultClient.Do(req)
            if err != nil {
                return nil, err
            }
            defer resp.Body.Close()
            return io.ReadAll(resp.Body)
        },
    )

    for i, result := range results {
        if errs[i] != nil {
            fmt.Printf("url[%d] error: %v\n", i, errs[i])
        } else {
            fmt.Printf("url[%d] got %d bytes\n", i, len(result))
        }
    }
}
```

### 双向 channel vs 单向 channel

