```go
// Race 并发向所有 URLs 发请求，返回最先成功的 n 个结果
func Race(ctx context.Context, urls []string, n int, timeout time.Duration) ([]string, error) {
    if n <= 0 || n > len(urls) {
        n = len(urls)
    }

    type result struct {
        url  string
        body string
        err  error
    }

    ctx, cancel := context.WithTimeout(ctx, timeout)
    defer cancel()

    resultCh := make(chan result, len(urls))

    for _, url := range urls {
        url := url
        go func() {
            req, err := http.NewRequestWithContext(ctx, "GET", url, nil)
            if err != nil {
                resultCh <- result{url: url, err: err}
                return
            }
            resp, err := http.DefaultClient.Do(req)
            if err != nil {
                resultCh <- result{url: url, err: err}
                return
            }
            defer resp.Body.Close()
            body, err := io.ReadAll(resp.Body)
            resultCh <- result{url: url, body: string(body), err: err}
        }()
    }

    var (
        successes []string
        lastErr   error
        received  int
    )

    for received < len(urls) && len(successes) < n {
        select {
        case r := <-resultCh:
            received++
            if r.err != nil {
                lastErr = r.err
            } else {
                successes = append(successes, r.body)
            }
        case <-ctx.Done():
            if len(successes) > 0 {
                return successes, nil
            }
            return nil, fmt.Errorf("timeout: got %d/%d results: %w", len(successes), n, ctx.Err())
        }
    }

    if len(successes) == 0 {
        return nil, fmt.Errorf("all requests failed, last error: %w", lastErr)
    }
    return successes, nil
}

// 使用
func main() {
    ctx := context.Background()
    mirrors := []string{
        "https://mirror1.example.com/file",
        "https://mirror2.example.com/file",
        "https://mirror3.example.com/file",
    }
    // 取最先成功的 1 个结果（类似 CDN 择优）
    results, err := Race(ctx, mirrors, 1, 5*time.Second)
    if err != nil {
        log.Fatal(err)
    }
    fmt.Println("fastest result:", results[0][:100])
}
```

question:
以下代码有几个并发问题？全部找出来并修复。

```go
type Server struct {
    connections map[string]net.Conn
    count       int
}

func (s *Server) Add(id string, conn net.Conn) {
    s.connections[id] = conn
    s.count++
}

func (s *Server) Remove(id string) {
    delete(s.connections, id)
    s.count--
}

func (s *Server) Get(id string) net.Conn {
    return s.connections[id]
}

func (s *Server) Count() int {
    return s.count
}

func (s *Server) Broadcast(msg []byte) {
    for _, conn := range s.connections {
        go func() {
            conn.Write(msg)
        }()
    }
}
```

answer:
### 发现的并发问题

**问题 1：map 并发读写（数据竞争）**
`connections` 是普通 map，多个 goroutine 并发调用 Add/Remove/Get 会触发 `fatal: concurrent map read and write`。

**问题 2：count 非原子操作（数据竞争）**
`s.count++` 是读-改-写三步操作，并发时结果不确定。

**问题 3：Broadcast 中的闭包捕获（循环变量陷阱）**
```go
for _, conn := range s.connections {
    go func() {
        conn.Write(msg)  // ❌ 捕获的是循环变量 conn 的引用
    }()
}
// 所有 goroutine 可能用的是同一个 conn（最后一个）
```

**问题 4：Broadcast 中 msg 的并发写风险**
若调用方在发送后修改了 `msg`（如 `msg` 是底层被复用的 buf），并发写入会有问题。

### 修复

```go
type Server struct {
    mu          sync.RWMutex
    connections map[string]net.Conn
    count       int64  // 用 atomic 操作
}

func (s *Server) Add(id string, conn net.Conn) {
    s.mu.Lock()
    defer s.mu.Unlock()
    s.connections[id] = conn
    atomic.AddInt64(&s.count, 1)
}

func (s *Server) Remove(id string) {
    s.mu.Lock()
    defer s.mu.Unlock()
    if _, ok := s.connections[id]; ok {
        delete(s.connections, id)
        atomic.AddInt64(&s.count, -1)
    }
}

func (s *Server) Get(id string) net.Conn {
    s.mu.RLock()
    defer s.mu.RUnlock()
    return s.connections[id]
}

func (s *Server) Count() int64 {
    return atomic.LoadInt64(&s.count)
}

func (s *Server) Broadcast(msg []byte) {
    // 复制 msg 防止调用方修改
    msgCopy := make([]byte, len(msg))
    copy(msgCopy, msg)

    s.mu.RLock()
    conns := make([]net.Conn, 0, len(s.connections))
    for _, conn := range s.connections {
        conns = append(conns, conn)
    }
    s.mu.RUnlock()  // 尽快释放读锁，不在锁内做 IO

    for _, conn := range conns {
        conn := conn  // ✅ 修复闭包捕获
        go func() {
            conn.Write(msgCopy)
        }()
    }
}
```

### 修复要点总结

1. 所有 map 操作用 `RWMutex` 保护
2. 计数器用 `atomic` 操作
3. 循环变量传参修复闭包捕获
4. IO 操作在锁外执行（减少锁持有时间）
5. 复制 `msg` 避免并发修改
